 348→router.get('/getNotifications', requireAuth, async(req, res) =>{
 349→    const {before} = req.query;
 350→    const userId = req.userId;
 351→    const parsedLimit = parseLimitWithinRange(
 352→        req.query.limit,
 353→        NOTIFICATION_LIMIT_MIN,
 354→        NOTIFICATION_LIMIT_MAX,
 355→        NOTIFICATION_DEFAULT_LIMIT
 356→    );
 357→
 358→    if(parsedLimit == null){
 359→        return res.status(400).json({error: `limit must be between ${NOTIFICATION_LIMIT_MIN} and ${NOTIFICATION_LIMIT_MAX}`});
 360→    }
 361→
 362→    // Fetch a generous amount from both tables, then merge and paginate
 363→    const fetchLimit = parsedLimit + 1;
 364→
 365→    let journalQuery = supabase
 366→    .from('notifications')
 367→    .select(NOTIFICATION_JOURNAL_SELECT)
 368→    .eq('receiver_id', userId)
 369→    .order('created_at', {ascending: false})
 370→    .order('id', {ascending: false})
 371→    .limit(fetchLimit)
 372→
 373→    let opinionQuery = supabase
 374→    .from('notification_opinions')
 375→    .select(NOTIFICATION_OPINION_SELECT)
 376→    .eq('receiver_id', userId)
 377→    .order('created_at', {ascending: false})
 378→    .order('id', {ascending: false})
 379→    .limit(fetchLimit)
 380→
 381→    if(before){
 382→        journalQuery = journalQuery.lt('created_at', before);
 383→        opinionQuery = opinionQuery.lt('created_at', before);
 384→    }
 385→
 386→    const [journalResult, opinionResult] = await Promise.all([journalQuery, opinionQuery]);
 387→
 388→    if(journalResult.error){
 389→        console.error('error while fetching data from notification table:', journalResult.error);
 390→        return res.status(500).json({error: 'error fetching data from notification table'});
 391→    }
 392→    if(opinionResult.error){
 393→        console.error('error while fetching data from notification_opinions table:', opinionResult.error);
 394→        return res.status(500).json({error: 'error fetching data from notification_opinions table'});
 395→    }
 396→
 397→    const journalNotifs = (journalResult.data || []).map(n => ({...n, source: 'journal'}));
 398→    const opinionNotifs = (opinionResult.data || []).map(n => ({...n, source: 'opinion'}));
 399→
 400→    // Merge and sort by created_at descending
 401→    const merged = [...journalNotifs, ...opinionNotifs]
 402→        .sort((a, b) => new Date(b.created_at) - new Date(a.created_at));
 403→
 404→    // Likes/bookmarks lookup only for journal notifications
 405→    const journalIds = [...new Set(
 406→        merged
 407→            .filter((n) => n.source === 'journal')
 408→            .map((n) => n.journal_id)
 409→            .filter(Boolean)
 410→    )];
 411→
 412→    let hasLikedResult = [];
 413→    let hasBookMarkedResult = [];
 414→    if(journalIds.length > 0){
 415→        const [hasLiked, hasBookMarked] = await Promise.all([
 416→            supabase.from('likes').select('journal_id').in('journal_id', journalIds).eq('user_id', userId),
 417→            supabase.from('bookmarks').select('journal_id').in('journal_id', journalIds).eq('user_id', userId)
 418→        ]);
 419→
 420→        if(hasLiked.error || hasBookMarked.error){
 421→            console.error('supabase error while fetching data:', hasLiked.error || hasBookMarked.error);
 422→        }
 423→        hasLikedResult = hasLiked.data || [];
 424→        hasBookMarkedResult = hasBookMarked.data || [];
 425→    }
 426→
 427→    const userHasLikedSet = new Set(hasLikedResult.map((likes) => likes.journal_id));
 428→    const userHasBookmarkedSet = new Set(hasBookMarkedResult.map((bookmarks) => bookmarks.journal_id));
 429→
 430→    const formatted = merged.map((notif) => ({
 431→        ...notif,
 432→        hasLiked: notif.source === 'journal' ? userHasLikedSet.has(notif.journal_id) : false,
 433→        hasBookMarked: notif.source === 'journal' ? userHasBookmarkedSet.has(notif.journal_id) : false
 434→    }))
 435→
 436→    const hasMore = formatted.length > parsedLimit;
 437→    const slicedData = hasMore ? formatted.slice(0, parsedLimit) : formatted;
 438→
 439→    return res.status(200).json(
 440→        {
 441→            hasMore: hasMore,
 442→            data: slicedData,
 443→        }
 444→    )
 445→
 446→})
