67→    .eq('following_id', userId)
68→
69→    const followingCountPromise = supabase
70→    .from('follows')
71→    .select('*', {count: 'exact', head: true})
72→    .eq('follower_id', userId)
73→
74→    const [userDataResult, followerCountResult, followingCountResult] = await Promise.all([
75→        userDataPromise, followerCountPromise, followingCountPromise
76→    ])
