 24→export const uploadUserDataService = async(bio, name, image, userId, userEmail, username) =>{
 25→    if(!userId){
 26→        throw {status: 400, error: 'userId is undefined'};
 27→    }
 28→    if(!name || typeof name !== 'string' || name.length > 20){
 29→        throw {status: 400, error: 'name should be a string and not more than 20 characters'}
 30→    }
 31→    if(!bio || typeof bio !== 'string' || bio.length > 150){
 32→        throw {status: 400, error: 'bio should be a string and not more than 150 characters'}
 33→    }
 34→
 35→    // Validate username if provided
 36→    let validatedUsername = null;
 37→    if(username && typeof username === 'string'){
 38→        const trimmed = username.trim().toLowerCase();
 39→        if(trimmed.length < 3 || trimmed.length > 50){
 40→            throw {status: 400, error: 'username must be 3-50 characters'};
 41→        }
 42→        if(!/^[a-z0-9-]+$/.test(trimmed)){
 43→            throw {status: 400, error: 'username can only contain lowercase letters, numbers, and hyphens'};
 44→        }
 45→        // Check uniqueness
 46→        const {data: existing} = await supabase
 47→            .from('users')
 48→            .select('id')
 49→            .ilike('username', trimmed)
 50→            .limit(1);
 51→        if(existing && existing.length > 0){
 52→            throw {status: 409, error: 'username is already taken'};
 53→        }
 54→        validatedUsername = trimmed;
 55→    }
 56→
 57→    let publicUrl = null;
 58→    if(image){
 59→        const dataUrl = await imageUploader(image, userId, 'avatars');
 60→
 61→        publicUrl = dataUrl;
 62→    }
 63→
 64→    const data = {
 65→        bio: bio,
 66→        name: name,
 67→        id: userId,
 68→        user_email: userEmail || null,
 69→        image_url: publicUrl ? publicUrl : null
 70→    }
 71→
 72→    if(validatedUsername){
 73→        data.username = validatedUsername;
 74→    }
 75→
 76→    const {data: uploadData, error:errorUploadData} = await supabase
 77→    .from('users')
 78→    .insert([data])
 79→
 80→    if(errorUploadData){
 81→        console.error('supabase error:', errorUploadData.message);
 82→        throw {status:500, error:'supabase error while uploading data'}
 83→    }
 84→
 85→    return true;
 86→}
