 88→export const completeOnboardingService = async(userId, writingInterests, writingGoal) => {
 89→    if(!userId){
 90→        throw {status: 400, error: 'userId is undefined'};
 91→    }
 92→
 93→    const payload = {
 94→        onboarding_completed: true,
 95→        onboarding_completed_at: new Date().toISOString(),
 96→    };
 97→
 98→    if(Array.isArray(writingInterests)){
 99→        payload.writing_interests = writingInterests.filter(i => typeof i === 'string').slice(0, 16);
100→    }
101→    if(writingGoal && typeof writingGoal === 'string'){
102→        payload.writing_goal = writingGoal;
103→    }
104→
105→    const {error} = await supabase
106→        .from('users')
107→        .update(payload)
108→        .eq('id', userId);
109→
110→    if(error){
111→        console.error('supabase error completing onboarding:', error.message);
112→        throw {status: 500, error: 'failed to complete onboarding'};
113→    }
114→
115→    // Fire-and-forget: generate interests embedding for personalized feed
116→    if(Array.isArray(writingInterests) && writingInterests.length > 0){
117→        updateUserInterestsEmbedding(userId, writingInterests)
118→            .catch(err => console.error('non-blocking interests embedding error:', err?.message || err));
119→    }
120→
121→    return true;
122→}
