router.get('/getFollowsData', async(req, res) => {
    const {userId, loggedInUserId} = req.query;
    if(!userId && !loggedInUserId) return res.status(400).json({error: 'userId or loggendUserId is undefined '});
    // console.log(req.query)
    try {
