    // Step 1: Fetch journals via RPC (subquery stays inside Postgres — scales to 100k+ followings)
    const { data: rpcData, error } = await supabase.rpc('get_following_feed', {
        p_user_id: userId,
        p_limit: parsedLimit + 1,
