11→export const handleCLickContent = (navigate) => {
12→    return (
13→        e,
14→        jsonbContent,
15→        wholeText,
16→        title,
17→        userId,
18→        name,
19→        avatar,
20→        created_at,
21→        journalId,
22→        isLiked,
23→        commentsCount,
24→        isBookmarked,
25→        likesCount,
26→        bookmarksCount,
27→        badge,
28→        postType = null,
29→        userReaction = null,
30→        reactionCount = 0
31→    ) => {
32→    e.stopPropagation()
33→
34→    const encodedJournalId = journalId ? encodeURIComponent(journalId) : '';
35→    const postSlug = slugifyTitle(title);
36→    const nextPath = journalId
37→        ? `/home/post/${encodedJournalId}${postSlug ? `/${postSlug}` : ''}`
38→        : '/home/contentViewer';
39→
40→    navigate(nextPath, {
41→        state: {
42→            content: jsonbContent,
43→            wholeText: wholeText,
44→            title: title,
45→            userId: userId,
46→            name: name,
47→            avatar: avatar,
48→            created_at: created_at,
49→            journalId: journalId,
50→            isLiked: isLiked,
51→            commentsCount: commentsCount,
52→            isBookmarked: isBookmarked,
53→            likesCount: likesCount,
54→            bookmarksCount: bookmarksCount,
55→            badge: badge,
56→            postType: postType,
57→            userReaction: userReaction,
58→            reactionCount: reactionCount
59→        }
60→    })
61→    }
62→
63→}
